import React from 'react' import { Navigate, Route, Routes } from 'react-router-dom' import LandingPage from './pages/LandingPage' import LoginPage from './pages/LoginPage' import RegisterPage from './pages/RegisterPage' import ProductsPage from './pages/ProductsPage' import UserProfilePage from './pages/UserProfilePage' import './App.css'
function App() { return ( <Routes> <Route path="/" element={<LandingPage />} /> <Route path="/products" element={<ProductsPage />} /> <Route path="/login" element={<LoginPage />} /> <Route path="/register" element={<RegisterPage />} /> <Route path="/me" element={<UserProfilePage />} /> <Route path="*" element={<Navigate to="/" replace />} /> </Routes> ) }
export default App

import React from 'react'
import { Link } from 'react-router-dom'

function getInitials(name) {
  if (!name) return 'U'
  const parts = name.trim().split(/\s+/).filter(Boolean)
  if (parts.length === 0) return 'U'
  if (parts.length === 1) return parts[0].slice(0, 1).toUpperCase()
  return `${parts[0][0]}${parts[parts.length - 1][0]}`.toUpperCase()
}

function AuthUserBadge({ session }) {
  if (!session?.token) {
    return (
      <div className="flex items-center gap-2">
        <Link to="/login" className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900">
          Đăng nhập
        </Link>
        <Link to="/register" className="hidden rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900 md:inline-flex">
          Đăng ký
        </Link>
      </div>
    )
  }

  const user = session.user || {}
  const displayName = user.fullName || user.username || 'Tài khoản'
  const avatarUrl = user.avatarUrl
  const initials = getInitials(displayName)

  return (
    <Link to="/me" className="flex items-center gap-2 rounded-full border border-zinc-300 bg-white px-3 py-2 text-xs font-semibold text-zinc-800 hover:border-zinc-900">
      {avatarUrl ? (
        <img src={avatarUrl} alt={displayName} className="h-7 w-7 rounded-full object-cover" />
      ) : (
        <span className="flex h-7 w-7 items-center justify-center rounded-full bg-zinc-900 text-[10px] font-bold text-white">
          {initials}
        </span>
      )}
      <span className="max-w-[120px] truncate">{displayName}</span>
    </Link>
  )
}

export default AuthUserBadge

import React, { useEffect, useMemo, useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import { clearAuth, getAuthSession, getCurrentUserDetail } from '../services/authApi'

function getInitials(name) {
  if (!name) return 'U'
  const parts = name.trim().split(/\s+/).filter(Boolean)
  if (parts.length === 0) return 'U'
  if (parts.length === 1) return parts[0].slice(0, 1).toUpperCase()
  return `${parts[0][0]}${parts[parts.length - 1][0]}`.toUpperCase()
}

function UserProfilePage() {
  const [session, setSession] = useState(() => getAuthSession())
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [userDetail, setUserDetail] = useState(null)
  const navigate = useNavigate()

  useEffect(() => {
    if (!session?.token) {
      navigate('/login', { replace: true })
      return
    }

    async function loadUserDetail() {
      setLoading(true)
      setError('')

      try {
        const detail = await getCurrentUserDetail()
        setUserDetail(detail)
      } catch (err) {
        setError(err?.message || 'Không thể tải thông tin tài khoản')
      } finally {
        setLoading(false)
      }
    }

    loadUserDetail()
  }, [navigate, session?.token])

  const user = useMemo(() => {
    return userDetail || session?.user || null
  }, [session?.user, userDetail])

  const displayName = user?.fullName || user?.username || 'Tài khoản'
  const avatarUrl = user?.avatarUrl

  const handleLogout = () => {
    clearAuth()
    toast.success('Đã đăng xuất')
    navigate('/login')
  }

  return (
    <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
      <div className="mx-auto w-full max-w-5xl">
        <header className="mb-8 flex flex-wrap items-center justify-between gap-3">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">SplitGo</p>
            <h1 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">Thông tin người dùng</h1>
          </div>
          <div className="flex items-center gap-3">
            <Link to="/products" className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900">
              Về sản phẩm
            </Link>
            <button onClick={handleLogout} className="rounded-full border border-red-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-red-700 hover:border-red-500">
              Đăng xuất
            </button>
          </div>
        </header>

        <section className="rounded-3xl border border-zinc-200 bg-white p-8 shadow-sm">
          <div className="flex flex-wrap items-center gap-4">
            {avatarUrl ? (
              <img src={avatarUrl} alt={displayName} className="h-20 w-20 rounded-full object-cover" />
            ) : (
              <div className="flex h-20 w-20 items-center justify-center rounded-full bg-zinc-900 text-xl font-bold text-white">
                {getInitials(displayName)}
              </div>
            )}

            <div>
              <p className="text-2xl font-semibold text-zinc-900">{displayName}</p>
              <p className="text-sm text-zinc-600">@{user?.username || 'unknown'}</p>
            </div>
          </div>

          {loading && <p className="mt-6 text-sm text-zinc-600">Đang tải thông tin tài khoản...</p>}
          {!loading && error && <p className="mt-6 rounded-2xl border border-amber-200 bg-amber-50 p-4 text-sm text-amber-800">{error}</p>}

          <div className="mt-6 grid gap-4 md:grid-cols-2">
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Email</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.email || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Vai trò</p>
              <p className="mt-1 font-medium text-zinc-900">{String(user?.role || session?.role || '-').replace('ROLE_', '')}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Số điện thoại</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.phone || '-'}</p>
            </div>
            <div className="rounded-2xl border border-zinc-200 bg-zinc-50 p-4">
              <p className="text-xs uppercase tracking-[0.16em] text-zinc-500">Địa chỉ</p>
              <p className="mt-1 font-medium text-zinc-900">{user?.address || '-'}</p>
            </div>
          </div>
        </section>
      </div>
    </div>
  )
}

export default UserProfilePage

const API_BASE = '/api'

async function parseResponse(response) {
  const payload = await response.json().catch(() => null)

  if (!response.ok) {
    throw new Error(payload?.message || `HTTP ${response.status}`)
  }

  if (payload && payload.success === false) {
    throw new Error(payload.message || 'Yêu cầu không thành công')
  }

  return payload
}

function normalizeAuthData(payload) {
  const data = payload?.data ?? null

  if (!data || typeof data !== 'object') {
    return data
  }

  const token = data.token || data.accessToken || data.jwt || null
  const refreshToken = data.refreshToken || data.token || data.jwt || null
  const user = data.user || data.a || data.profile || data

  return {
    ...data,
    token,
    refreshToken,
    user,
  }
}

export function getStoredAuth() {
  const raw = localStorage.getItem('splitgo_auth')
  if (!raw) return null

  try {
    return JSON.parse(raw)
  } catch {
    return null
  }
}

export function getStoredToken() {
  return localStorage.getItem('splitgo_token') || ''
}

export function getStoredRefreshToken() {
  return localStorage.getItem('splitgo_refresh_token') || getStoredToken()
}

export function clearAuth() {
  localStorage.removeItem('splitgo_auth')
  localStorage.removeItem('splitgo_token')
  localStorage.removeItem('splitgo_refresh_token')
}

export async function login(payload) {
  const response = await fetch(`${API_BASE}/auth/login`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })

  const apiResponse = await parseResponse(response)
  return {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }
}

export async function register(payload) {
  const response = await fetch(`${API_BASE}/auth/register`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
  })

  const apiResponse = await parseResponse(response)
  return {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }
}

export function persistAuthResult(payload) {
  if (!payload?.data) return

  const authData = payload.data
  localStorage.setItem('splitgo_auth', JSON.stringify(authData))

  if (authData.token) {
    localStorage.setItem('splitgo_token', authData.token)
    localStorage.setItem('splitgo_refresh_token', authData.refreshToken || authData.token)
  }
}

export async function refreshAuthToken(token = getStoredRefreshToken()) {
  if (!token) {
    throw new Error('Không có token để làm mới')
  }

  const response = await fetch(`${API_BASE}/auth/refresh`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ token }),
  })

  const apiResponse = await parseResponse(response)
  const normalized = {
    ...apiResponse,
    data: normalizeAuthData(apiResponse),
  }

  persistAuthResult(normalized)
  return normalized
}

export async function authFetch(input, init = {}) {
  const headers = new Headers(init.headers || {})
  const token = getStoredToken()

  if (token) {
    headers.set('Authorization', `Bearer ${token}`)
  }

  const response = await fetch(input, {
    ...init,
    headers,
  })

  if (response.status !== 401) {
    return response
  }

  const refreshed = await refreshAuthToken()
  const nextHeaders = new Headers(init.headers || {})
  const nextToken = refreshed?.data?.token || getStoredToken()

  if (nextToken) {
    nextHeaders.set('Authorization', `Bearer ${nextToken}`)
  }

  return fetch(input, {
    ...init,
    headers: nextHeaders,
  })
}

